${contextDocs ? `\nRelevant context from the knowledge base:\n${contextDocs}` : ""}${upcomingEventsContext}${seasonContext}${recentPostsContext}`;

  const messages = [
    ...historyMessages.map((m) => ({ role: m.role, content: m.content })),
