// ── Mock DB (Kysely chain) ────────────────────────────────────────────────
const createMockQuery = () => {
  const q: any = {
    select: vi.fn(),
    where: vi.fn(),
    orderBy: vi.fn(),
    limit: vi.fn(),
    execute: vi.fn().mockResolvedValue([]),
    executeTakeFirst: vi.fn().mockResolvedValue(null),
